## 2.  C/C++ stub – `pcapng_stubs.cpp`

> **NOTE** – The stub is written as a *single* C++ translation unit that
> can be compiled with `g++` (or any C++ compiler that understands the
> OCaml C‑API).  The only external symbols that we need from *libpcapng*
> are the iterator class and a small data structure that represents a
> captured frame.  For the purpose of this example we assume the following
> simplified C++ API (replace with the real one you have):

```cpp
//--- libpcapng.hpp (simplified, for illustration only) --------------------
namespace pcapng {

struct Frame {
    uint64_t ts;          // nanoseconds since the epoch
    const uint8_t* data; // pointer into the underlying file buffer
    size_t len;           // length of data
};

class Iterator {
public:
    explicit Iterator(const std::string& filename); // throws std::runtime_error
    ~Iterator();

    // Return true if a next frame is available; false = end of stream.
    bool next(Frame& out);
};

} // namespace pcapng
//--- end of libpcapng.hpp -------------------------------------------------
```

> The real library will probably have a more elaborate API – adapt the
> wrapper code accordingly.

### 2.1  Header & helper macros

```cpp
/* pcapng_stubs.cpp ---------------------------------------------------------
 *
 *  OCaml <-> C++ glue for libpcapng.
 *
 *  Build command (example):
 *    ocamlc -c pcapng.ml
 *    g++ -I$(OCAML_HOME)/include -fPIC -c pcapng_stubs.cpp
 *    ocamlc -custom -o pcapng_test pcapng.cmo pcapng_stubs.o -lstdc++ -lpcapng
 *
 * -------------------------------------------------------------------------- */

extern "C" {
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/bigarray.h>
#include <caml/fail.h>
}

/* Include the (real) libpcapng header.  Here we just reuse the tiny stub
 * defined above. */
#include "libpcapng.hpp"

using namespace pcapng;
```

### 2.2  Custom block that owns a `pcapng::Iterator*`

```cpp
/* ----------------------------------------------------------------------
   The OCaml value that holds a pointer to the C++ iterator.
   ---------------------------------------------------------------------- */

static void finalize_iterator(value v)
{
    /* The custom block stores the pointer directly (no indirection). */
    Iterator* it = (Iterator*)Data_custom_val(v);
    delete it;
}

/* No need for compare, hash or serialize – we keep the defaults. */
static struct custom_operations iterator_ops = {
    "pcapng.iterator.1",          /* identifier, must be unique */
    finalize_iterator,
    custom_compare_default,
    custom_hash_default,
    custom_serialize_default,
    custom_deserialize_default,
    custom_compare_ext_default,
    custom_fixed_length_default
};

/* Helper that extracts the iterator pointer from an OCaml value and checks
 * that it is non‑NULL.  Raises Failure if the value has been closed. */
static Iterator* get_iterator(value v)
{
    Iterator* it = (Iterator*)Data_custom_val(v);
    if (it == nullptr) caml_failwith("Pcapng: iterator already closed");
    return it;
}
```

### 2.3  Helper to build an OCaml `frame` value

```cpp
/* ----------------------------------------------------------------------
   Build an OCaml value of type `Pcapng.frame` (a record).  The record
   layout is known at compile time – we can allocate a block with three
   fields: ts (int64), data (bytes), len (int).  The `frame` type is
   defined in the .mli as a record, so the compiler will generate a
   descriptor that we can reuse at run‑time.
   ---------------------------------------------------------------------- */

static value caml_alloc_frame(const Frame& f)
{
    CAMLparam0();
    CAMLlocal3(ocaml_ts, ocaml_data, ocaml_frame);

    /* 1) timestamp – OCaml int64 is a boxed 64‑bit integer */
    ocaml_ts = caml_copy_int64((int64_t)f.ts);

    /* 2) data – copy the raw bytes into an OCaml string (bytes). */
    ocaml_data = caml_alloc_initialized_string(f.len,
                     reinterpret_cast<const char*>(f.data));

    /* 3) length – plain int */
    value ocaml_len = Val_int(f.len);   /* assumes len fits into an OCaml int */

    /* 4) build the record.  The compiler generates a block with the same
     *    layout as a tuple of three fields.  We can therefore allocate a
     *    three‑field block and fill the fields directly. */
    ocaml_frame = caml_alloc(3, 0);     /* tag 0 = regular block */
    Store_field(ocaml_frame, 0, ocaml_ts);
    Store_field(ocaml_frame, 1, ocaml_data);
    Store_field(ocaml_frame, 2, ocaml_len);

    CAMLreturn(ocaml_frame);
}
```

### 2.4  `open_file` – create the iterator and wrap it in a custom block

```cpp
extern "C" CAMLprim value caml_pcapng_open_file(value v_path)
{
    CAMLparam1(v_path);
    CAMLlocal1(v_res);

    const char* path = String_val(v_path);
    Iterator* it = nullptr;

    try {
        it = new Iterator(std::string(path));
    } catch (const std::exception& e) {
        caml_failwith(e.what());
    }

    /* Allocate a custom block that holds the raw pointer. */
    v_res = caml_alloc_custom(&iterator_ops,
                              sizeof(Iterator*),   /* size */
                              0,  /* mem: not used for GC */
                              1); /* finalizer runs immediately */
    Data_custom_val(v_res) = (char*)it;   /* store the pointer */

    CAMLreturn(v_res);
}
```

### 2.5  `close` – explicit finalisation (optional but nice)

```cpp
extern "C" CAMLprim value caml_pcapng_close(value v_it)
{
    CAMLparam1(v_it);
    Iterator* it = get_iterator(v_it);
    delete it;
    Data_custom_val(v_it) = nullptr;   /* mark as closed */
    CAMLreturn(Val_unit);
}
```

### 2.6  `next` – pull‑style iterator returning an `option`

```cpp
extern "C" CAMLprim value caml_pcapng_next(value v_it)
{
    CAMLparam1(v_it);
    CAMLlocal1(v_opt);
    Iterator* it = get_iterator(v_it);
    Frame f;

    if (!it->next(f)) {
        /* End of stream – return None */
        v_opt = Val_int(0);                /* 0 = None */
    } else {
        /* Some frame – build the OCaml record and wrap it in Some */
        value v_frame = caml_alloc_frame(f);
        v_opt = caml_alloc(1, 0);          /* Some = block with tag 0, 1 field */
        Store_field(v_opt, 0, v_frame);
    }

    CAMLreturn(v_opt);
}
```

### 2.7  `iter` – push‑style iteration with a user supplied closure

```cpp
extern "C" CAMLprim value caml_pcapng_iter(value v_it, value v_closure)
{
    CAMLparam2(v_it, v_closure);
    CAMLlocal1(v_frame);
    Iterator* it = get_iterator(v_it);
    Frame f;

    /* The closure may raise; we must catch it and re‑raise so that the
     * OCaml side sees the exception.  The normal OCaml convention is to
     * use caml_callback_exn. */
    while (it->next(f)) {
        v_frame = caml_alloc_frame(f);
        value exn = caml_callback_exn(v_closure, v_frame);
        if (Is_exception_result(exn)) {
            /* Propagate the exception to the caller. */
            caml_raise(exn);
        }
    }

    CAMLreturn(Val_unit);
}
```

### 2.8  Register the primitives (for `ocamlc -custom` linking)

```cpp
static struct caml_named_value {
    const char *name;
    value (*fn) (value);
} caml_named_values[] = {
    { "pcapng_open_file",   caml_pcapng_open_file },
    { "pcapng_close",       caml_pcapng_close },
    { "pcapng_next",        caml_pcapng_next },
    { "pcapng_iter",        caml_pcapng_iter },
    { nullptr, nullptr }
};

extern "C" CAMLprim value caml_pcapng_register_primitives(value unit)
{
    CAMLparam1(unit);
    for (int i = 0; caml_named_values[i].name != nullptr; ++i) {
        caml_register_named_value(caml_named_values[i].name,
                                  caml_named_values[i].fn);
    }
    CAMLreturn(Val_unit);
}
```

### 2.9  Stub file for OCaml – `pcapng_stubs.c` (generated automatically)

You do **not** need a separate `.c` file; the above `pcapng_stubs.cpp`
already contains the C‑compatible entry points (`extern "C"`).  The only
thing you have to do in the OCaml side is to bind the primitives using
`external`.

---

## 3.  OCaml side – glue that calls the C primitives

Create a file `pcapng.ml` that implements the public interface by binding
the primitives we just registered:

```ocaml
(* pcapng.ml --------------------------------------------------------------- *)
open Caml

type t = private Obj.t   (* opaque – we never construct it manually *)

type frame = {
  ts   : int64;
  data : bytes;
  len  : int;
}

external register_primitives : unit -> unit = "caml_pcapng_register_primitives"

let () = register_primitives ()

external open_file : string -> t = "pcapng_open_file"
external close    : t -> unit = "pcapng_close"
external next     : t -> frame option = "pcapng_next"
external iter     : t -> (frame -> unit) -> unit = "pcapng_iter"

(* Helper to make the type `t` abstract – we hide the underlying Obj.t. *)
let open_file path = open_file path
let close = close
let next = next
let iter = iter
```

The `type t = private Obj.t` trick tells the OCaml type‑checker that
`pcapng.ml` itself can create values of type `t`, but users of the
library cannot pattern‑match on them.  The actual value is the custom
block allocated in `caml_pcapng_open_file`.

