## 4.  Minimal `Makefile` snippet

```make
OCAMLFLAGS = -thread -g
CXXFLAGS   = -O2 -Wall -I$(shell ocamlc -where)

all: pcapng.cma libpcapng_stubs.o

pcapng.cma: pcapng.cmo pcapng_stubs.o
    ocamlc -a -o $@ $^

pcapng.cmo: pcapng.ml pcapng.mli
    ocamlc $(OCAMLFLAGS) -c pcapng.ml

pcapng_stubs.o: pcapng_stubs.cpp libpcapng.hpp
    g++ -c -fPIC $(CXXFLAGS) -o $@ $<

clean:
    rm -f *.cmi *.cmo *.o *.cma
```

*Replace `libpcapng.hpp` and the linking flags (`-lpcapng`) with the real
library you are using.*

---

## 5.  Example usage (in OCaml)

```ocaml
(* test.ml -------------------------------------------------------------- *)
let () =
  let it = Pcapng.open_file "sample.pcapng" in
  Printf.printf "Iterating with a closure …\n";
  Pcapng.iter it (fun frame ->
      Printf.printf "ts=%Ld len=%d\n%!" frame.ts frame.len);
  (* Or pull‑style: *)
  Printf.printf "Pull‑style iteration …\n";
  let rec loop () =
    match Pcapng.next it with
    | None -> ()
    | Some f ->
        Printf.printf "ts=%Ld len=%d\n%!" f.ts f.len;
        loop ()
  in
  loop ();
  Pcapng.close it
```

Compile & run:

```sh
$ ocamlc -c test.ml
$ ocamlc -o test pcapng.cma test.cmo -cclib -lpcapng -cclib -lstdc++
$ ./test
Iterating with a closure …
ts=1627845600123456789 len=60
…
Pull‑style iteration …
ts=1627845600123456789 len=60
…
```

